import React, { useState } from "react";
import * as ReactDOM from "react-dom";
// import "./login.css"; // Assuming you have your CSS file or you can style inline
import {
  FireBaseGoogleLogin,
  loginWithEmailandPassword,
} from "./firebaseLogin";
import FireBaseLogout from "./firebaseLogout";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faGoogle, faFacebook } from "@fortawesome/free-brands-svg-icons";
import registerwithEmailPassword from "./firebaseRegister";
import { userInfo } from "os";
import { onAuthStateChanged } from "firebase/auth";
import { auth } from "../Firebase/googleFirebaseConfig";

const LoginRegister: React.FC = () => {
  onAuthStateChanged(auth, (user) => {
    if (user) {
      // User is signed in.
      alert("User is logged in");
      alert("User ID:  " + user.uid);
      alert("Email:  " + user.email);
    } else {
      // User is not signed in.
      alert("User is not logged in");
    }
  });

  // Managing the tab state
  const [isLogin, setIsLogin] = useState(true);
  const [message, setMessage] = useState("");
  const [registerFormData, registerSetFormData] = useState({
    userName: "",
    email: "",
    password: "",
    reEnterPassword: "",
  });
  const [loginFormData, setLoginFormData] = useState({
    loginUsername: "",
    loginPassword: "",
  });

  const showLogin = () => setIsLogin(true);
  const showRegister = () => setIsLogin(false);

  async function loginWithGoogle() {
    await FireBaseGoogleLogin();
    window.location.href = "./home.html";
    // document.getElementById("login_page").style.display = "none";
    // document.getElementById("container").style.display = "block";
    return <></>;
  }

  async function handleRegisterFormData(e) {
    e.preventDefault();
    const { name, value } = e.target;
    registerSetFormData((prevData) => ({
      ...prevData,
      [name]: value,
    }));
  }

  async function handleLoginFormData(e) {
    e.preventDefault();
    const { name, value } = e.target;
    setLoginFormData((prevData) => ({
      ...prevData,
      [name]: value,
    }));
  }

  async function submitRegisterFormData() {
    try {
      setMessage(await registerwithEmailPassword(registerFormData));
      showLogin();
    } catch (error) {
      throw error;
    }
  }

  async function submitLoginFormData() {
    setMessage(await loginWithEmailandPassword(loginFormData));
  }

  return (
    <div className="mainDiv">
      <div className="login_card">
        {/* Tabs for Login and Register */}
        <div className="tab-container">
          <div
            className={`tab ${isLogin ? "active" : "inactive"}`}
            onClick={showLogin}
          >
            Login
          </div>
          <div
            className={`tab ${!isLogin ? "active" : "inactive"}`}
            onClick={showRegister}
          >
            Register
          </div>
        </div>

        {/* Login Form */}
        {isLogin && (
          <div id="login-form" className="mt-4">
            <p>{message}</p>
            <form onSubmit={submitLoginFormData}>
              <div className="mb-3">
                <label htmlFor="loginUsername" className="form-label">
                  User Name
                </label>
                <input
                  type="text"
                  className="form-control"
                  id="loginUsername"
                  name="loginUsername"
                  placeholder="Enter user name"
                  onChange={handleLoginFormData}
                />
              </div>
              <div className="mb-3">
                <label htmlFor="loginPassword" className="form-label">
                  Password
                </label>
                <input
                  type="password"
                  className="form-control"
                  id="loginPassword"
                  name="loginPassword"
                  placeholder="Enter password"
                  onChange={handleLoginFormData}
                />
              </div>
              <div className="center-buttons">
                <button type="submit" className="btn-primary">
                  Login
                </button>
              </div>
            </form>
          </div>
        )}

        {/* Register Form */}
        {!isLogin && (
          <div id="register-form" className="mt-4">
            <form onSubmit={submitRegisterFormData}>
              <div className="mb-3">
                <label htmlFor="registerUsername" className="form-label">
                  User Name
                </label>
                <input
                  type="text"
                  className="form-control"
                  id="registerUsername"
                  placeholder="Enter user name"
                  name="userName"
                  onChange={handleRegisterFormData}
                />
              </div>
              <div className="mb-3">
                <label htmlFor="registerEmail" className="form-label">
                  Email ID
                </label>
                <input
                  type="email"
                  className="form-control"
                  id="registerEmail"
                  placeholder="Enter email id"
                  name="email"
                  onChange={handleRegisterFormData}
                />
              </div>
              <div className="mb-3">
                <label htmlFor="registerPassword" className="form-label">
                  Password
                </label>
                <input
                  type="password"
                  className="form-control"
                  id="registerPassword"
                  placeholder="Enter password"
                  name="password"
                  onChange={handleRegisterFormData}
                />
              </div>
              <div className="mb-3">
                <label htmlFor="registerRePassword" className="form-label">
                  Re-enter Password
                </label>
                <input
                  type="password"
                  className="form-control"
                  id="registerRePassword"
                  placeholder="Re-enter password"
                  name="reEnterPassword"
                  onChange={handleRegisterFormData}
                />
              </div>
              <div className="center-buttons">
                <button type="submit" className="btn-primary">
                  Register
                </button>
              </div>
            </form>
          </div>
        )}

        {/* Social Login Icons */}
        <div className="social-icons">
          <div className="btn-social-google" onClick={() => loginWithGoogle()}>
            <FontAwesomeIcon icon={faGoogle} />
          </div>
          <div className="btn-social-facebook">
            <FontAwesomeIcon icon={faFacebook} />
          </div>
        </div>
      </div>
    </div>
  );
};

ReactDOM.render(<LoginRegister />, document.getElementById("login_page"));

export default LoginRegister;

const logout = async () => {
  await FireBaseLogout();
  window.location.href = "./index.html";
  // document.getElementById("login_page").style.display = "block";
  // document.getElementById("container").style.display = "none";
};

