import * as ReactDOM from "react-dom";
import * as React from "react";
import {
  GoogleAuthProvider,
  signInWithEmailAndPassword,
  signInWithPopup,
  signInWithRedirect,
  signInAnonymously,
  getAuth,
} from "firebase/auth";
import app, { auth } from "../Firebase/googleFirebaseConfig";

export async function FireBaseGoogleLogin() {
  const provider = await new GoogleAuthProvider();
  return signInWithPopup(auth, provider);
  return <></>;
}
export async function loginWithEmailandPassword(formData) {
  try {
    const auth = getAuth();
    const email = formData["loginUsername"];
    const password = formData["loginPassword"];
    alert("emaillllll: " + email + " password: " + password);
    const userCredentials = await signInWithEmailAndPassword(
      auth,
      email,
      password
    );
    alert(userCredentials.user);
    return userCredentials.user;
  } catch (error) {
    alert(error.message);
    return error.message;
  }
}

export default FireBaseGoogleLogin;
